  { icon: Bot, label: 'Interrogation des IA (ChatGPT, Claude, Gemini, AI Overviews)...', duration: 3000 },
  { icon: BarChart3, label: 'Analyse des 50+ critères AEO...', duration: 2500 },
  { icon: CheckCircle, label: 'Génération du rapport...', duration: 1500 },
];

interface AnalyzeProps {
  onAnalyze: (url: string) => void;
  isAnalyzing: boolean;
}

const Analyze: React.FC<AnalyzeProps> = ({ onAnalyze, isAnalyzing }) => {
  const [inputUrl, setInputUrl] = useState('');
  const [currentStep, setCurrentStep] = useState(0);

  useEffect(() => {
    if (!isAnalyzing) { setCurrentStep(0); return; }
    let step = 0;
    setCurrentStep(0);
    const timers: ReturnType<typeof setTimeout>[] = [];
    let accumulated = 0;
    analysisSteps.forEach((s, i) => {
      if (i > 0) {
        accumulated += analysisSteps[i - 1].duration;
        timers.push(setTimeout(() => setCurrentStep(i), accumulated));
      }
    });
    return () => timers.forEach(clearTimeout);
  }, [isAnalyzing]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (inputUrl && !isAnalyzing) {
      onAnalyze(inputUrl);
    }
  };

  return (
    <div className="w-full px-4 min-h-[80vh] flex flex-col items-center justify-center animate-in fade-in duration-500">

      <div className="text-center mb-10 space-y-4">
        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.04] border border-white/[0.08] text-purple-400 text-sm font-medium">
          <Sparkles size={14} />
          <span>Audit AEO & GEO Instantané</span>
        </div>
        <h1 className="text-4xl md:text-5xl font-sans font-bold text-white">
          Analysez votre <span className="gradient-text">visibilité IA</span>
        </h1>
        <p className="text-xl text-gray-500 max-w-2xl mx-auto">
          Découvrez comment les moteurs de réponse perçoivent votre contenu et obtenez un plan d'action pour être cité.
        </p>
      </div>

      <div className="w-full max-w-3xl relative z-10">
        <div className="absolute inset-0 bg-primary/20 blur-3xl rounded-full opacity-20 -z-10"></div>
        <form onSubmit={handleSubmit}>
          <div className="ninja-card p-8">
            <div className="flex items-center gap-3">
              <Search className="text-gray-500 shrink-0" size={24} />
              <input
                type="url"
                required
                placeholder="https://votre-site.com"
                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl focus:ring-1 focus:ring-purple-500/30 focus:border-purple-500/30 text-white placeholder-gray-500 text-lg px-4 py-4"
                value={inputUrl}
                onChange={(e) => setInputUrl(e.target.value)}
                autoFocus
              />
              <button
                type="submit"
                disabled={isAnalyzing}
                className={`btn-gradient px-8 py-4 shrink-0 transition-all transform hover:scale-105 ${isAnalyzing ? '!bg-gray-600 cursor-not-allowed opacity-60' : ''}`}
              >
                {isAnalyzing ? 'Analyse...' : 'Lancer l\'audit'}
              </button>
            </div>
          </div>
        </form>

        {!isAnalyzing && (
          <div className="flex justify-center gap-8 mt-8 text-sm text-gray-500">
            <span className="flex items-center gap-2"><ShieldCheck size={16} className="text-purple-400"/> Analyse Sécurisée</span>
            <span className="flex items-center gap-2"><TrendingUp size={16} className="text-purple-400"/> +50 Critères GEO</span>
          </div>
        )}

        {isAnalyzing && (
          <div className="mt-8 w-full max-w-md mx-auto space-y-3 animate-in fade-in duration-300">
            {analysisSteps.map((step, i) => {
              const StepIcon = step.icon;
              const isActive = i === currentStep;
              const isDone = i < currentStep;
              return (
                <div key={i} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-500 ${
                  isActive ? 'bg-purple-500/10 border border-purple-500/20' : isDone ? 'bg-white/[0.02] border border-white/[0.04]' : 'opacity-40 border border-transparent'
                }`}>"}

